module sr_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output reg Qn
);
    always @(posedge clk) begin
        if (S && !R) begin
            obf_Q <= 1;
            Qn <= 0;
        end else if (!S && R) begin
            obf_Q <= 0;
            Qn <= 1;
        end
        // If S=0 and R=0, obf_Q holds its state
        // If S=1 and R=1, obf_Q holds its state (undefined behavior)
    end
endmodule
